+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?/g, '\
');
+}
+
+function trimLines(lines: string[], enabled: boolean): string[] {
+  return enabled ? lines.map((line, index) => (index === 0 ? line : line.replace(/^\\s+/, ''))) : lines;
+}
+
+function isInternalFrame(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']): boolean {
+  const node = line.includes('node:internal');
+  const superjson = /src\\/(?:transformer|plainer|index)\\.ts/.test(line);
+  return (mode === 'node' && node) || (mode === 'superjson' && superjson) || (mode === 'node_and_superjson' && (node || superjson));
+}
+
+function redactLine(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'none') return line;
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/');
+    return line.replace(new RegExp(cwd.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&'), 'g'), '');
+  }
+  return line.replace(/(?:[A-Za-z]:[\\\\/]|\\/)[^\\s()]+/g, path => {
+    const parts = path.replace(/\\\\/g, '/').split('/');
+    return parts[parts.length - 1];
+  });
+}
+
+function linesFromStack(stack: string, options: NormalizedErrorStackOptions): string[] {
+  const source = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  return trimLines(source.split('\
'), options.trimLeadingWhitespace);
+}
+
+export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
+  let lines = linesFromStack(stack, options);
+  lines = lines.map(line => redactLine(line, options.redactPaths));
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  return [lines[0], ...lines.slice(1).filter(line => !isInternalFrame(line, options.stripInternalFrames))].join('\
');
+}
+
+export function processStackFrames(stack: string, options: NormalizedErrorStackOptions): { raw: string }[] {
+  let lines = linesFromStack(stack, options);
+  lines = [lines[0], ...lines.slice(1).filter(line => !isInternalFrame(line, options.stripInternalFrames))];
+  lines = lines.map(line => redactLine(line, options.redactPaths));
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  return lines.map(raw => ({ raw }));
+}
